354	/// `todos/<id>.md` per todo, and a sweep that deletes the per-todo files of
355	/// todos that no longer exist.
356	pub(crate) fn project_todos(ws: &Path, todos: &[Todo]) -> io::Result<()> {
357	    fs::create_dir_all(todos_dir(ws))?;
358	    atomic_write(&todos_index_path(ws), &render_todos_index_md(todos))?;
