364	    let live: HashSet<u64> = todos.iter().map(|t| t.id).collect();
365	    if let Ok(entries) = fs::read_dir(todos_dir(ws)) {
366	        for entry in entries.flatten() {
367	            let name = entry.file_name();
368	            let stem = match name.to_string_lossy().strip_suffix(".md") {
369	                Some(stem) => stem.to_string(),
370	                None => continue,
371	            };
372	            if let Ok(id) = stem.parse::<u64>() {
373	                if !live.contains(&id) {
374	                    let _ = fs::remove_file(entry.path());
375	                }
376	            }
377	        }
378	    }
379	    Ok(())
380	}
