fn sync_agent_labels(&mut self) {
    let agent_ids: Vec<u32> = self
        .panes
        .iter()
        .filter(|p| p.role == PaneRole::Agent)
        .filter_map(|p| match p.id {
            PaneId::Terminal(tid) => Some(tid),
