198	/// Two-strike shutdown: the first SIGTERM (or Ctrl-C) refuses to exit if
199	/// MCP clients are still connected and logs a per-project count so the
200	/// operator can see what they would drop. A second SIGTERM within the
201	/// confirmation window exits regardless. SIGKILL bypasses this by design.
202	///
203	/// When no clients are connected the very first signal exits cleanly,
204	/// matching the prior behaviour - the guard only engages when there is
205	/// something to protect. Keeping the second-signal window short means a
206	/// determined operator can still exit in roughly the time it takes to
207	/// hit Ctrl-C twice.
208	async fn shutdown_when_safe(state: Arc<Mutex<Store>>) {
209	    use tokio::time::{timeout, Duration};
210	
211	    /// How long the daemon waits for a second SIGTERM after refusing the
212	    /// first. Long enough for a deliberate "ok, I really mean it" repeat,
213	    /// short enough that a forgotten daemon does not stay refusing forever.
214	    const CONFIRM_WINDOW: Duration = Duration::from_secs(10);
215	
216	    loop {
217	        if tokio::signal::ctrl_c().await.is_err() {
218	            return;
219	        }
220	        let counts = {
221	            let st = state.lock().expect("state mutex poisoned");
222	            (st.connected_agent_count(), st.connected_agents_by_project())
223	        };
224	        if counts.0 == 0 {
225	            tracing::info!("shutdown signal received");
226	            return;
227	        }
228	        for (project, n) in &counts.1 {
229	            tracing::warn!(
230	                project = ?project,
231	                agents = *n,
232	                "SIGTERM refused: MCP clients still connected"
233	            );
234	        }
235	        tracing::warn!(
236	            total = counts.0,
237	            window_secs = CONFIRM_WINDOW.as_secs(),
238	            "send another SIGTERM within {}s to force shutdown",
239	            CONFIRM_WINDOW.as_secs()
240	        );
241	        match timeout(CONFIRM_WINDOW, tokio::signal::ctrl_c()).await {
242	            Ok(_) => {
243	                tracing::warn!("second shutdown signal received - exiting");
244	                return;
245	            }
246	            Err(_) => {
247	                tracing::info!("shutdown window elapsed; continuing to serve");
248	                // Loop and wait for the next signal afresh.
249	            }
250	        }
251	    }
252	}
