/// When no clients are connected the very first signal exits cleanly,
/// matching the prior behaviour - the guard only engages when there is
/// something to protect. Keeping the second-signal window short means a
/// determined operator can still exit in roughly the time it takes to
/// hit Ctrl-C twice.
async fn shutdown_when_safe(state: Arc<Mutex<Store>>) {
    use tokio::time::{timeout, Duration};

    /// How long the daemon waits for a second SIGTERM after refusing the
    /// first. Long enough for a deliberate "ok, I really mean it" repeat,
    /// short enough that a forgotten daemon does not stay refusing forever.
    const CONFIRM_WINDOW: Duration = Duration::from_secs(10);

    loop {
        if tokio::signal::ctrl_c().await.is_err() {
            return;
        }
        let counts = {
            let st = state.lock().expect("state mutex poisoned");
            (st.connected_agent_count(), st.connected_agents_by_project())
        };
        if counts.0 == 0 {
            tracing::info!("shutdown signal received");
            return;
        }
        for (project, n) in &counts.1 {
            tracing::warn!(
                project = ?project,
                agents = *n,
                "SIGTERM refused: MCP clients still connected"
            );
        }
        tracing::warn!(
            total = counts.0,
            window_secs = CONFIRM_WINDOW.as_secs(),
            "send another SIGTERM within {}s to force shutdown",
            CONFIRM_WINDOW.as_secs()
        );
        match timeout(CONFIRM_WINDOW, tokio::signal::ctrl_c()).await {
            Ok(_) => {
                tracing::warn!("second shutdown signal received - exiting");
                return;
            }
            Err(_) => {
                tracing::info!("shutdown window elapsed; continuing to serve");
                // Loop and wait for the next signal afresh.
            }
        }
    }
}

    self.reproject_agents(project)
}

/// The registry entry for agent `key`, if it is registered in `project`.
pub fn agent_whoami(&self, project: ProjectId, key: &str) -> Option<Agent> {
    self.registry.get(project.0, key)
}

/// Every agent registered in `project`, after pruning silent ones.
pub fn agent_list(&mut self, project: ProjectId) -> Result<Vec<Agent>, CoreError> {
    self.prune_agents(project)?;
    Ok(self.registry.list(project.0))
}

/// Total number of agents currently connected, across every project. The
/// daemon's SIGTERM guard uses this to decide whether shutting down
/// would drop live MCP clients. Does not prune - the caller is the
/// signal handler and a stale count is preferable to running prune
/// logic in the signal path.
pub fn connected_agent_count(&self) -> usize {
    self.registry.total()
}

/// `(project_id, agent_count)` for every project with at least one
/// connected agent. The daemon logs this on SIGTERM so the operator can
/// see what a second SIGTERM would drop.
pub fn connected_agents_by_project(&self) -> Vec<(ProjectId, usize)> {
    self.registry
        .counts_by_project()
        .into_iter()
        .map(|(pid, n)| (ProjectId(pid), n))
        .collect()
}

