    pub(crate) fn counts_by_project(&self) -> Vec<(i64, usize)> {
        let mut counts: Vec<(i64, usize)> = self
            .by_project
            .iter()
            .filter(|(_, m)| !m.is_empty())
            .map(|(pid, m)| (*pid, m.len()))
            .collect();
        counts.sort_by_key(|(pid, _)| *pid);
