//! `panopt agent-config` - emit a Claude Code `--mcp-config` JSON for a
//! hand-launched agent.
//!
//! Bridges the gap between cockpit-spawned agents (which get a stable id and
//! identity via the env-templated config at `mcp.rs`) and agents started
//! manually with `claude --mcp-config ...`. Without this, a hand-launched
//! agent falls back to the rotating MCP session id and shows up in the
//! registry as a ghost that other agents cannot pin down (DESIGN.md §9).
//!
//! The emitted config bakes the resolved `ws`, `agent`, `name`, and `token`
//! straight into the URL so a hand-launched session is identical in shape to
//! a cockpit-spawned one - no PANOPT_* env vars required on the caller.

use std::path::PathBuf;

use anyhow::{Context, Result};
use percent_encoding::{utf8_percent_encode, NON_ALPHANUMERIC};
use serde_json::json;

use crate::paths;

/// Emit the `--mcp-config` JSON to stdout.
pub fn run(
    host: Option<String>,
    port: u16,
    id: Option<String>,
    name: Option<String>,
    ws: Option<PathBuf>,
) -> Result<()> {
    let host = host.unwrap_or_else(|| "127.0.0.1".into());
    let id = id.unwrap_or_else(default_id);
    let name = name.unwrap_or_else(|| id.clone());
    let ws = resolve_ws(ws)?;
    let token = panopt_core::auth::read_token(&paths::token()?)
        .context("reading the panopt token (start the daemon with `panopt up`)")?;

    let encode = |s: &str| utf8_percent_encode(s, NON_ALPHANUMERIC).to_string();
    let url = format!(
        "http://{}:{}/mcp?ws={}&agent={}&name={}&token={}",
        host,
        port,
        encode(&ws.to_string_lossy()),
        encode(&id),
        encode(&name),
        encode(&token),
    );
    let cfg = json!({
        "mcpServers": {
            "panopt": {
                "type": "http",
                "url": url,
            }
        }
    });
    println!("{}", serde_json::to_string_pretty(&cfg)?);
    Ok(())
}

