91	/// that agent, and `agent_leave` removes the entry and releases its locks.
92	/// Best-effort: missing daemon or missing agent are no-ops the caller logs
93	/// but does not surface.
94	pub fn leave(ws: Option<PathBuf>, id: String, port: u16) -> Result<()> {
95	    let ws = resolve_ws(ws)?;
96	    let token = panopt_core::auth::read_token(&paths::token()?)
97	        .context("reading the panopt token (start the daemon with `panopt up`)")?;
98	    let encode = |s: &str| utf8_percent_encode(s, NON_ALPHANUMERIC).to_string();
