100	        "http://127.0.0.1:{port}/mcp?ws={}&agent={}&token={}",
101	        encode(&ws.to_string_lossy()),
102	        encode(&id),
103	        encode(&token),
104	    );
105	    let client = Client::connect(&url).context("connecting to the panopt daemon")?;
106	    let result = client.call("agent_leave", json!({}));
107	    client.close();
108	    result.map(|_| ())
109	}
